  "userdoc": {
    "kind": "user",
    "methods": {
      "getChildren(address)": {
        "notice": "查询某个节点的子节点地址（left, right）"
      },
      "getNodeWorth(address)": {
        "notice": "查询某个节点余额"
      },
      "getOptimalParent(address,address)": {
        "notice": "获取“推荐的父节点”（小区最小策略：优先走子树价值更小的一侧）"
      },
      "getParent(address)": {
        "notice": "查询某个节点的父节点地址"
      },
      "getRecommender(address)": {
        "notice": "查询某个节点的推荐人地址"
      },
      "initPrice((address,uint256)[2][6])": {
        "notice": "只能调用一次，调用前必须确保支持的代币地址已经初始化，不需要检查token地址是否初始化，因为在构造函数中，初始化了TC"
      },
      "initRoot(address)": {
        "notice": "初始化根节点（只能执行一次，且只能由合约部署者/owner 调用）"
      },
      "insert(address,address,bool)": {
        "notice": "插入节点"
      },
      "isExist(address)": {
        "notice": "判断某个地址是否已在树中"
      },
      "root()": {
        "notice": "根节点地址（初始化后不可更改）"
      },
      "subtreeWorth(address)": {
        "notice": "返回某个节点子树（含该节点）余额总和，用于计算某个节点及其左右子树的有效NFT总价值"
      },
      "totalTreeWorth()": {
        "notice": "遍历整颗二叉树，返回所有节点余额总和"
      }
    },
    "version": 1
  }
